+    fn execute_prepared_direct_simple_insert_with_cursor<P: PageReader + PageWriter>(
+        &self,
+        execution_cx: &Cx,
+        direct: &PreparedDirectSimpleInsert,
+        explicit_rowid: Option<i64>,
+        prepared_append_hint: &mut Option<PreparedDirectInsertAppendHint>,
+        memdb_next_rowid_hint: Option<i64>,
+        mem_row_values: &mut PreparedDirectInsertRowScratch,
+        track_memdb_delta: bool,
+        defer_memdb_upsert: bool,
+        defer_lazy_memdb_materialization: bool,
+        can_use_prebuilt_constant_record: bool,
