+                    execution_cx,
+                    cached_leaf,
+                    rowid,
+                    record_bytes,
+                )?
+            {
+                append_fast_leaf_page = Some(cached_leaf.leaf_page());
+                Ok(())
+            } else {
+                match cursor.table_try_append_rightmost_leaf_hint_known_last_rowid_with_state(
+                    execution_cx,
+                    append_hint.leaf_page,
+                    append_hint.last_rowid,
+                    rowid,
+                    record_bytes,
+                )? {
+                    Some(cached_leaf) => {
+                        append_fast_leaf_page = Some(cached_leaf.leaf_page());
+                        append_hint.cached_leaf =
+                            Some(self.prepare_prepared_direct_insert_cached_leaf_hint(cached_leaf));
+                        Ok(())
+                    }
+                    None => {
+                        cursor.table_append_after_last_position(execution_cx, rowid, record_bytes)
+                    }
+                }
+            }
+        } else if append_fast_path_candidate {
+            cursor.table_append_after_last_position(execution_cx, rowid, record_bytes)
+        } else {
+            cursor.table_insert(execution_cx, rowid, record_bytes)
+        };
+        let mut record_append_hint = false;
+        let mut append_leaf_page = None;
+        match insert_result {
+            Ok(()) => {
+                if append_fast_path_candidate {
+                    record_append_hint = true;
+                    append_leaf_page = append_fast_leaf_page.or_else(|| cursor.current_page());
+                    if prepared_append_hint
