+                    self.clear_prepared_direct_insert_append_hint();
+                    return Ok(None);
+                }
+                fsqlite_ast::ConflictAction::Replace => {
+                    self.clear_prepared_direct_insert_append_hint();
+                    if !cursor.table_move_to(execution_cx, rowid)?.is_found() {
+                        return Err(FrankenError::PrimaryKeyViolation);
+                    }
+                    cursor.delete(execution_cx)?;
+                    cursor.table_insert(execution_cx, rowid, record_bytes)?;
+                }
+                fsqlite_ast::ConflictAction::Rollback
+                | fsqlite_ast::ConflictAction::Abort
+                | fsqlite_ast::ConflictAction::Fail => {
+                    self.clear_prepared_direct_insert_append_hint();
+                    return Err(FrankenError::PrimaryKeyViolation);
+                }
+            },
+            Err(error) => {
+                self.clear_prepared_direct_insert_append_hint();
+                return Err(error);
+            }
+        }
+        if record_append_hint {
+            if let Some(mut append_hint) = prepared_append_hint.take() {
+                append_hint.last_rowid = rowid;
+                if let Some(leaf_page) = append_leaf_page {
+                    append_hint.leaf_page = leaf_page;
+                }
+                if append_cached_leaf.is_some() {
+                    append_hint.cached_leaf = append_cached_leaf;
+                }
+                self.store_prepared_direct_insert_append_hint(Some(append_hint));
+            } else {
+                self.store_prepared_direct_insert_append_hint(Some(
+                    PreparedDirectInsertAppendHint {
+                        root_page: direct.root_page,
+                        leaf_page: append_leaf_page.ok_or_else(|| {
+                            FrankenError::internal(
+                                "prepared direct insert append hint missing leaf page",
+                            )
+                        })?,
+                        last_rowid: rowid,
+                        cached_leaf: append_cached_leaf,
+                    },
+                ));
+            }
+        } else {
+            self.clear_prepared_direct_insert_append_hint();
+        }
+        record_hot_path_duration(
+            &FSQLITE_PREPARED_DIRECT_INSERT_BTREE_INSERT_TIME_NS,
+            btree_insert_start,
+        );
+        if !can_use_prebuilt_constant_record && let Some(ipk_idx) = direct.rowid_alias_col_idx {
+            mem_row_values[ipk_idx] = SqliteValue::Integer(rowid);
+        }
+        let memdb_apply_start = profile_enabled.then(Instant::now);
+        if track_memdb_delta {
+            // Explicit transactions still need exact deferred row deltas because
+            // SAVEPOINT / in-txn reads can force a MemDatabase boundary before
+            // COMMIT. Autocommit `:memory:` writes do not: both retained-
+            // autocommit batches and the cached-write-txn fast path leave the
+            // compatibility mirror stale and repair it lazily on the next read
+            // boundary.
+            if defer_memdb_upsert {
+                let owned_values = std::mem::take(mem_row_values).into_vec();
+                self.pending_memdb_direct_upserts
+                    .borrow_mut()
+                    .push(PendingMemdbDirectUpsert {
+                        root_page: direct.root_page,
+                        rowid,
+                        num_columns: direct.columns.len(),
+                        values: owned_values,
+                    });
+            } else if defer_lazy_memdb_materialization {
+                mem_row_values.clear();
+                self.abandon_exact_memdb_row_mirror();
+            } else {
+                let owned_values = std::mem::take(mem_row_values).into_vec();
+                self.apply_prepared_direct_insert_memdb_row(
+                    direct.root_page,
+                    direct.columns.len(),
+                    rowid,
+                    owned_values,
+                );
+            }
+        } else {
+            mem_row_values.clear();
+            self.abandon_exact_memdb_row_mirror();
+        }
+        record_hot_path_duration(
+            &FSQLITE_PREPARED_DIRECT_INSERT_MEMDB_APPLY_TIME_NS,
+            memdb_apply_start,
+        );
+        Ok(Some(rowid))
+    }
